import{_ as a,o as t,c as o,a2 as i}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Feudalism","description":"","frontmatter":{},"headers":[],"relativePath":"boxed-sets/feudalism.md","filePath":"boxed-sets/feudalism.md","lastUpdated":1782025909000}'),r={name:"boxed-sets/feudalism.md"};function n(s,e,l,h,c,d){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="feudalism" tabindex="-1">Feudalism <a class="header-anchor" href="#feudalism" aria-label="Permalink to &quot;Feudalism&quot;">​</a></h1><p>Status: concept sketch.</p><p>Feudalism is a <a href="./../formats/bang-like/">BANG-like hidden-role</a> game-night set built around the monarch mechanic.</p><h2 id="concept" tabindex="-1">Concept <a class="header-anchor" href="#concept" aria-label="Permalink to &quot;Concept&quot;">​</a></h2><p>The King role starts the game as the monarch. At the start of the King&#39;s turn, if the King is not the monarch, the King becomes the monarch.</p><p>The point is that the table can fight over who currently holds power, but power keeps returning to the crown until someone manages to break that structure. A Renegade-style role can win by properly dethroning the King.</p><h2 id="deck-notes" tabindex="-1">Deck Notes <a class="header-anchor" href="#deck-notes" aria-label="Permalink to &quot;Deck Notes&quot;">​</a></h2><ul><li>All decks should feature monarch cards or care about becoming the monarch.</li><li>Each deck needs to function with any role it is assigned.</li><li>The set should reward fighting over the monarch without making the King impossible to pressure.</li></ul><h2 id="source-family" tabindex="-1">Source Family <a class="header-anchor" href="#source-family" aria-label="Permalink to &quot;Source Family&quot;">​</a></h2><p>This set is currently inspired by the BANG/Kingdom/Treachery family of Commander variants. Keep the detailed source references on the <a href="./../formats/bang-like/">BANG-like formats page</a>.</p><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><ul><li>What are the exact roles and win conditions?</li><li>Does the King receive a life, card, or tempo bonus beyond recurring monarchy?</li><li>Should becoming monarch reveal information, trigger role abilities, or act only as a resource engine?</li><li>How many prebuilt decks does the first box need?</li></ul>',12)])])}const p=a(r,[["render",n]]);export{m as __pageData,p as default};
